def find_greater(capital, cp):
    lo = 0
    hi = len(cp)

    while lo < hi:
        mid = (lo + hi) // 2
        if cp[mid][0] <= capital:
            lo = mid + 1
        else:
            hi = mid

    return lo


def solve(costs, profits, capital, m):
    cp = sorted(zip(costs, profits))
    max_profits = []

    for _, profit in cp:
        if not max_profits:
            max_profits.append(profit)
        else:
            max_profits.append(max(max_profits[-1], profit))

    for _ in range(m):
        i = find_greater(capital, cp) - 1
        if i < len(cp) and cp[i][0] <= capital:
            capital += max_profits[i]

    return capital
